# Mathematical utilities module

# Returns the sum of a list of integers
def sum_list(numbers: list[int]) -> int:
    total: int = 0
    for n in numbers:
        total += n
    return total

# Returns the average of a list of floats
def average(values: list[float]) -> float:
    if len(values) == 0:
        return 0.0
    total: float = 0.0
    for v in values:
        total += v
    return total / float(len(values))

# Checks if a number is prime
def is_prime(n: int) -> bool:
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    i: int = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i += 2
    return True

class Statistics:
    data: list[float]
    count: int

    def __init__(self, values: list[float]):
        self.data = [v for v in values]  # copy
        self.count = len(values)

    def min_val(self) -> float:
        if self.count == 0:
            return 0.0
        min_value: float = self.data[0]
        for v in self.data:
            if v < min_value:
                min_value = v
        return min_value

    def max_val(self) -> float:
        if self.count == 0:
            return 0.0
        max_value: float = self.data[0]
        for v in self.data:
            if v > max_value:
                max_value = v
        return max_value

    def range(self) -> float:
        return self.max_val() - self.min_val()

