# String utilities module - imports from math_utils for examples

from math_utils import sum_list

class TextFormatter:
    prefix: str

    def __init__(self, prefix: str):
        self.prefix = prefix

    def format(self, message: str) -> str:
        return self.prefix + ": " + message

    def repeat(self, text: str, times: int) -> str:
        result: str = ""
        i: int = 0
        while i < times:
            result += text
            i += 1
        return result

# Returns the total length of all strings in a list
def total_length(strings: list[str]) -> int:
    lengths: list[int] = [len(s) for s in strings]
    return sum_list(lengths)

# Checks if a string is a palindrome
def is_palindrome(s: str) -> bool:
    left: int = 0
    right: int = len(s) - 1
    while left < right:
        if str(s[left]) != str(s[right]):
            return False
        left += 1
        right -= 1
    return True

# Reverses a string
def reverse_string(s: str) -> str:
    result: str = ""
    for c in s:
        result = str(c) + result
    return result

# Counts vowels in a string
def count_vowels(s: str) -> int:
    vowels: str = "aeiouAEIOU"
    count: int = 0
    for c in s:
        if str(c) in vowels:
            count += 1
    return count
